import 'chunk_text_decoder.dart';

Stream<String> parseEventData(Stream<List<int>> bytes) async* {
  var pending = '';
  await for (final piece in decodeByteChunks(bytes)) {
    pending += piece;
    while (true) {
      final newline = pending.indexOf('\n');
      if (newline < 0) break;
      final line = pending.substring(0, newline);
      pending = pending.substring(newline + 1);
      if (line.startsWith('data:')) {
        yield line.substring(5).trimLeft();
      }
    }
  }
}

